export default defineContract({
  name: 'auth',
  description: 'Handles user authentication, session management, and authorization utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/auth/login',   auth: false },
      { method: 'POST', path: '/auth/logout',  auth: true },
      { method: 'GET',  path: '/auth/session', auth: true },
      { method: 'POST', path: '/auth/password-reset-confirm', auth: false }, // New route for password reset confirmation
    ],
    functions: ['requireUser', 'getSession', 'createSession', 'invalidateSession', 'resetPassword'], // Added resetPassword
    types: ['User', 'Session', 'AuthError', 'PasswordResetToken'], // Added PasswordResetToken
  },

  sideEffects: [
    'writes to: sessions table',
    'reads from: users table',
    'writes to: password_reset_tokens table', // Added for password reset
    'reads from: password_reset_tokens table', // Added for password reset
  ],

  invariants: [
    'A session must always be bound to exactly one user',
    'Expired sessions must never be returned as valid',
    'Logout must invalidate the session immediately',
    'Password reset tokens must be one-time use and expire', // Added for password reset
    'Password reset must invalidate all existing sessions for the user', // Added for password reset
  ],
});
