import { query, transaction } from 'lib/db';
import { User, Session, PasswordResetToken } from 'modules/auth/types';

// --- User Queries ---

export async function findUserById(userId: string): Promise<User | null> {
  const result = await query<User>('SELECT id, email, password_hash as "passwordHash", created_at as "createdAt", updated_at as "updatedAt" FROM users WHERE id = $1', [userId]);
  return result.rows[0] || null;
}

export async function findUserByEmail(email: string): Promise<User | null> {
  const result = await query<User>('SELECT id, email, password_hash as "passwordHash", created_at as "createdAt", updated_at as "updatedAt" FROM users WHERE email = $1', [email]);
  return result.rows[0] || null;
}

export async function updateUserPassword(userId: string, newPasswordHash: string): Promise<void> {
  await query('UPDATE users SET password_hash = $1, updated_at = NOW() WHERE id = $2', [newPasswordHash, userId]);
}

// --- Session Queries ---

export async function createSession(userId: string, expiresAt: Date): Promise<Session> {
  const result = await query<Session>(
    'INSERT INTO sessions (user_id, expires_at) VALUES ($1, $2) RETURNING id, user_id as "userId", expires_at as "expiresAt", created_at as "createdAt"',
    [userId, expiresAt]
  );
  return result.rows[0];
}

export async function findSessionById(sessionId: string): Promise<Session | null> {
  const result = await query<Session>(
    'SELECT id, user_id as "userId", expires_at as "expiresAt", created_at as "createdAt" FROM sessions WHERE id = $1 AND expires_at > NOW()',
    [sessionId]
  );
  return result.rows[0] || null;
}

export async function invalidateSession(sessionId: string): Promise<void> {
  await query('DELETE FROM sessions WHERE id = $1', [sessionId]);
}

export async function invalidateAllUserSessions(userId: string): Promise<void> {
  await query('DELETE FROM sessions WHERE user_id = $1', [userId]);
}

// --- Password Reset Token Queries ---

export async function findPasswordResetToken(token: string): Promise<PasswordResetToken | null> {
  const result = await query<PasswordResetToken>(
    `SELECT id, user_id as "userId", token, expires_at as "expiresAt", used_at as "usedAt", created_at as "createdAt"
     FROM password_reset_tokens
     WHERE token = $1`,
    [token]
  );
  return result.rows[0] || null;
}

export async function invalidatePasswordResetToken(tokenId: string): Promise<void> {
  await query('UPDATE password_reset_tokens SET used_at = NOW() WHERE id = $1', [tokenId]);
}

/**
 * Performs a transactional update for password reset:
 * 1. Updates the user's password.
 * 2. Invalidates the password reset token.
 * 3. Invalidates all existing sessions for that user.
 *
 * @param userId The ID of the user whose password is being reset.
 * @param newPasswordHash The bcrypt hash of the new password.
 * @param passwordResetTokenId The ID of the password reset token to invalidate.
 */
export async function performPasswordResetTransaction(
  userId: string,
  newPasswordHash: string,
  passwordResetTokenId: string
): Promise<void> {
  await transaction(async (client) => {
    // 1. Update user's password
    await client.query('UPDATE users SET password_hash = $1, updated_at = NOW() WHERE id = $2', [newPasswordHash, userId]);

    // 2. Invalidate the password reset token
    await client.query('UPDATE password_reset_tokens SET used_at = NOW() WHERE id = $1', [passwordResetTokenId]);

    // 3. Invalidate all existing sessions for the user
    await client.query('DELETE FROM sessions WHERE user_id = $1', [userId]);
  });
}
